  'src/utils/crypto.js': `const crypto = require('crypto');

function deriveKey(secret) {
  return crypto.createHash('sha256').update(secret).digest();
}

function encrypt(text, secret) {
  const iv = crypto.randomBytes(16);
  const key = deriveKey(secret);
  const cipher = crypto.createCipheriv('aes-256-cbc', key, iv);
  const encrypted = Buffer.concat([cipher.update(String(text), 'utf8'), cipher.final()]);
  return iv.toString('hex') + ':' + encrypted.toString('hex');
}

function decrypt(payload, secret) {
  if (!payload) return '';
  const [ivHex, encryptedHex] = String(payload).split(':');
  const iv = Buffer.from(ivHex, 'hex');
  const key = deriveKey(secret);
  const decipher = crypto.createDecipheriv('aes-256-cbc', key, iv);
  const decrypted = Buffer.concat([decipher.update(Buffer.from(encryptedHex, 'hex')), decipher.final()]);
  return decrypted.toString('utf8');
}

module.exports = { encrypt, decrypt };
`,
  'src/db/schema.sql': `CREATE EXTENSION IF NOT EXISTS "uuid-ossp";

CREATE TABLE IF NOT EXISTS users (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  username TEXT UNIQUE NOT NULL,
  password_hash TEXT NOT NULL,
  role TEXT NOT NULL,
  failed_attempts INT NOT NULL DEFAULT 0,
  lockout_until TIMESTAMPTZ,
  last_active_at TIMESTAMPTZ,
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS patients (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  name TEXT NOT NULL,
  ssn_encrypted TEXT,
  allergies JSONB NOT NULL DEFAULT '[]'::jsonb,
  contraindications JSONB NOT NULL DEFAULT '[]'::jsonb,
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS icd_catalog (
  code TEXT PRIMARY KEY,
  label TEXT NOT NULL,
  active BOOLEAN NOT NULL DEFAULT TRUE,
  version_tag TEXT NOT NULL DEFAULT 'local-v1'
