  prescriber_id UUID NOT NULL REFERENCES users(id),
  drug_name TEXT NOT NULL,
  dose TEXT NOT NULL,
  route TEXT NOT NULL,
  quantity INT NOT NULL,
  instructions TEXT NOT NULL,
  override_reason TEXT,
  state TEXT NOT NULL DEFAULT 'draft',
  version INT NOT NULL DEFAULT 1,
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS inventory_items (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  sku TEXT UNIQUE NOT NULL,
  name TEXT NOT NULL,
  on_hand INT NOT NULL DEFAULT 0,
  low_stock_threshold INT NOT NULL DEFAULT 10,
  lot_tracking BOOLEAN NOT NULL DEFAULT FALSE,
  serial_tracking BOOLEAN NOT NULL DEFAULT FALSE
);

CREATE TABLE IF NOT EXISTS inventory_movements (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  item_id UUID NOT NULL REFERENCES inventory_items(id),
  movement_type TEXT NOT NULL,
  quantity INT NOT NULL,
  ref_type TEXT,
  ref_id UUID,
  lot TEXT,
  serial TEXT,
  reason TEXT,
  created_by UUID REFERENCES users(id),
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS invoices (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  patient_id UUID NOT NULL REFERENCES patients(id),
  lines JSONB NOT NULL DEFAULT '[]'::jsonb,
  subtotal NUMERIC(12,2) NOT NULL DEFAULT 0,
  plan_discount NUMERIC(12,2) NOT NULL DEFAULT 0,
  coupon_discount NUMERIC(12,2) NOT NULL DEFAULT 0,
  threshold_discount NUMERIC(12,2) NOT NULL DEFAULT 0,
  total NUMERIC(12,2) NOT NULL DEFAULT 0,
  state TEXT NOT NULL DEFAULT 'unpaid',
  payment_ref TEXT,
  version INT NOT NULL DEFAULT 1,
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS credentialing_profiles (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  entity_type TEXT NOT NULL,
  full_name TEXT NOT NULL,
  license_number TEXT,
  license_expiry DATE,
  status TEXT NOT NULL DEFAULT 'pending',
  version INT NOT NULL DEFAULT 1,
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS audit_events (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  entity_type TEXT NOT NULL,
  entity_id UUID NOT NULL,
  action TEXT NOT NULL,
  actor_id UUID,
  actor_role TEXT,
  event_data JSONB NOT NULL,
  snapshot JSONB NOT NULL,
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

INSERT INTO icd_catalog (code, label) VALUES ('J06.9', 'Acute upper respiratory infection, unspecified') ON CONFLICT DO NOTHING;
INSERT INTO icd_catalog (code, label) VALUES ('E11.9', 'Type 2 diabetes mellitus without complications') ON CONFLICT DO NOTHING;
