          <tbody>
            <tr *ngFor="let p of profiles">
              <td>{{ p.full_name }}</td>
              <td>{{ p.entity_type }}</td>
              <td>{{ p.license_number || '-' }}</td>
              <td>{{ p.license_expiry || '-' }}</td>
              <td>{{ p.status }}</td>
            </tr>
            <tr *ngIf="!profiles.length"><td colspan="5">No profiles yet.</td></tr>
          </tbody>
        </table>
      </article>

      <p class="msg">{{ message }}</p>
    </section>
  `,
